        ans = []
        path = []
        n = len(candidates)

        def dfs(start, remain):
            if remain == 0:
                ans.append(path.copy())
                return
            for i in range(start, n):
                if candidates[i] > remain:
                    break  # prune: further numbers are too large
                if i > start and candidates[i] == candidates[i - 1]:
                    continue  # skip duplicates at the same recursion level
                path.append(candidates[i])
                dfs(i + 1, remain - candidates[i])
                path.pop()

        dfs(0, target)
        return ans

Replace the O(n^2) counting + pop loop with an in-place two-pointer O(n) solution. This keeps at most two copies of each number and runs in linear time:

class Solution:
    def removeDuplicates(self, nums: List[int]) -> int:
        if len(nums) <= 2:
            return len(nums)
        write = 2
        for read in range(2, len(nums)):
            if nums[read] != nums[write - 2]:
                nums[write] = nums[read]
                write += 1
        return write

Why this is faster:
- The original used nums.count(...) and nums.pop(...), causing repeated scanning/shifting (O(n^2) worst-case).
- The two-pointer approach does a single pass with constant-time writes, O(n) time and O(1) extra space.

