class Solution:
    def findEvenNumbers(self, digits: List[int]) -> List[int]:
        # count available digits
        cnt = [0] * 10
        for d in digits:
            cnt[d] += 1
        res = []
        # enumerate all 3-digit even numbers (already in ascending order)
        for num in range(100, 1000, 2):
            a = num // 100
            b = (num // 10) % 10
            c = num % 10
            if a == b == c:
