                    res.append(num)
            elif b == c:
                if cnt[b] >= 2 and cnt[a] >= 1:
                    res.append(num)
            else:
                if cnt[a] >= 1 and cnt[b] >= 1 and cnt[c] >= 1:
                    res.append(num)
        return res

